	} else {
		reason = "legacy lifecycle metadata removed without lifecycle status change"
	}

	return lifecycleMigrationPlan{
		index:                 index,
		fromStatus:            b.Status,
		targetStatus:          target,
		reason:                reason,
		externalBlockerReason: externalReason,
		removeLabels:          legacyLabels,
		clearFields:           legacyFields,
